-- Luxx Client Hub schema. Run once in Supabase SQL Editor.
create extension if not exists pgcrypto;
do $$ begin create type public.user_role as enum ('admin','client'); exception when duplicate_object then null; end $$;
do $$ begin create type public.content_status as enum ('draft','internal_review','client_review','changes_requested','approved','scheduled','posted'); exception when duplicate_object then null; end $$;
create table if not exists public.clients (id uuid primary key default gen_random_uuid(),name text not null,slug text unique not null,created_at timestamptz not null default now());
create table if not exists public.profiles (id uuid primary key references auth.users(id) on delete cascade,client_id uuid references public.clients(id) on delete set null,full_name text,role public.user_role not null default 'client',created_at timestamptz not null default now());
create table if not exists public.content_items (id uuid primary key default gen_random_uuid(),client_id uuid not null references public.clients(id) on delete cascade,title text not null,content_type text,caption text,preview_url text,scheduled_for timestamptz,status public.content_status not null default 'draft',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.comments (id uuid primary key default gen_random_uuid(),content_item_id uuid not null references public.content_items(id) on delete cascade,author_id uuid not null references public.profiles(id) on delete cascade,body text not null,created_at timestamptz not null default now());
create table if not exists public.documents (id uuid primary key default gen_random_uuid(),client_id uuid not null references public.clients(id) on delete cascade,name text not null,category text not null,file_path text not null,created_at timestamptz not null default now());
create table if not exists public.invoices (id uuid primary key default gen_random_uuid(),client_id uuid not null references public.clients(id) on delete cascade,invoice_number text,amount_cents integer not null check(amount_cents>=0),status text not null default 'due',due_date date,file_path text,created_at timestamptz not null default now());
create table if not exists public.requests (id uuid primary key default gen_random_uuid(),client_id uuid not null references public.clients(id) on delete cascade,created_by uuid not null references public.profiles(id) on delete cascade,request_type text not null,details text not null,preferred_deadline date,status text not null default 'open',created_at timestamptz not null default now());
create or replace function public.is_admin() returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from public.profiles where id=(select auth.uid()) and role='admin')$$;
create or replace function public.my_client_id() returns uuid language sql stable security definer set search_path=public as $$select client_id from public.profiles where id=(select auth.uid())$$;
grant execute on function public.is_admin() to authenticated; grant execute on function public.my_client_id() to authenticated;
alter table public.clients enable row level security;alter table public.profiles enable row level security;alter table public.content_items enable row level security;alter table public.comments enable row level security;alter table public.documents enable row level security;alter table public.invoices enable row level security;alter table public.requests enable row level security;
drop policy if exists "clients select" on public.clients; create policy "clients select" on public.clients for select to authenticated using(id=public.my_client_id() or public.is_admin());
drop policy if exists "clients admin write" on public.clients; create policy "clients admin write" on public.clients for all to authenticated using(public.is_admin()) with check(public.is_admin());
drop policy if exists "profiles select" on public.profiles; create policy "profiles select" on public.profiles for select to authenticated using(id=(select auth.uid()) or public.is_admin());
drop policy if exists "profiles admin write" on public.profiles; create policy "profiles admin write" on public.profiles for all to authenticated using(public.is_admin()) with check(public.is_admin());
drop policy if exists "content select" on public.content_items; create policy "content select" on public.content_items for select to authenticated using(client_id=public.my_client_id() or public.is_admin());
drop policy if exists "content insert" on public.content_items; create policy "content insert" on public.content_items for insert to authenticated with check(public.is_admin());
drop policy if exists "content update" on public.content_items; create policy "content update" on public.content_items for update to authenticated using(client_id=public.my_client_id() or public.is_admin()) with check(client_id=public.my_client_id() or public.is_admin());
drop policy if exists "content delete" on public.content_items; create policy "content delete" on public.content_items for delete to authenticated using(public.is_admin());
drop policy if exists "comments select" on public.comments; create policy "comments select" on public.comments for select to authenticated using(exists(select 1 from public.content_items c where c.id=content_item_id and(c.client_id=public.my_client_id() or public.is_admin())));
drop policy if exists "comments insert" on public.comments; create policy "comments insert" on public.comments for insert to authenticated with check(author_id=(select auth.uid()) and exists(select 1 from public.content_items c where c.id=content_item_id and(c.client_id=public.my_client_id() or public.is_admin())));
drop policy if exists "documents select" on public.documents; create policy "documents select" on public.documents for select to authenticated using(client_id=public.my_client_id() or public.is_admin());
drop policy if exists "documents admin write" on public.documents; create policy "documents admin write" on public.documents for all to authenticated using(public.is_admin()) with check(public.is_admin());
drop policy if exists "invoices select" on public.invoices; create policy "invoices select" on public.invoices for select to authenticated using(client_id=public.my_client_id() or public.is_admin());
drop policy if exists "invoices admin write" on public.invoices; create policy "invoices admin write" on public.invoices for all to authenticated using(public.is_admin()) with check(public.is_admin());
drop policy if exists "requests select" on public.requests; create policy "requests select" on public.requests for select to authenticated using(client_id=public.my_client_id() or public.is_admin());
drop policy if exists "requests insert" on public.requests; create policy "requests insert" on public.requests for insert to authenticated with check((client_id=public.my_client_id() and created_by=(select auth.uid())) or public.is_admin());
drop policy if exists "requests admin update" on public.requests; create policy "requests admin update" on public.requests for update to authenticated using(public.is_admin()) with check(public.is_admin());
-- Automatically create an unassigned client profile for new auth users.
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$begin insert into public.profiles(id,full_name,role) values(new.id,coalesce(new.raw_user_meta_data->>'full_name',new.email),'client') on conflict(id) do nothing;return new;end;$$;
drop trigger if exists on_auth_user_created on auth.users;create trigger on_auth_user_created after insert on auth.users for each row execute procedure public.handle_new_user();
